@import url('https://fonts.googleapis.com/css2?family=Outfit:wght@300;400;500;600;700;800&family=Plus+Jakarta+Sans:wght@300;400;500;600;700;800&display=swap');

:root {
  /* Color Tokens */
  --bg-primary: #080B11;
  --bg-secondary: #0F1420;
  --bg-tertiary: #171E30;

  --glass-bg: rgba(15, 20, 32, 0.65);
  --glass-border: rgba(255, 255, 255, 0.08);
  --glass-border-hover: rgba(255, 255, 255, 0.15);
  --glass-shadow: rgba(0, 0, 0, 0.4);

  --text-primary: #F3F4F6;
  --text-secondary: #9CA3AF;
  --text-muted: #6B7280;

  --accent-primary: #8B5CF6; /* Glowing Violet */
  --accent-primary-hover: #7C3AED;
  --accent-secondary: #3B82F6; /* Electric Blue */

  --success: #10B981; /* Emerald Green */
  --success-glow: rgba(16, 185, 129, 0.15);
  --danger: #EF4444; /* Ruby Red */
  --danger-glow: rgba(239, 68, 68, 0.15);
  --warning: #F59E0B; /* Amber Yellow */

  --font-display: 'Outfit', sans-serif;
  --font-body: 'Plus Jakarta Sans', sans-serif;

  --transition-smooth: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
  --transition-bounce: all 0.5s cubic-bezier(0.175, 0.885, 0.32, 1.275);
}

/* Base resets */
* {
  box-sizing: border-box;
  padding: 0;
  margin: 0;
}

html, body {
  width: 100%;
  height: 100%;
  background: var(--bg-primary);
  color: var(--text-primary);
  font-family: var(--font-body);
  -webkit-font-smoothing: antialiased;
  overflow-x: hidden;
}

body {
  background-image: 
    radial-gradient(circle at 10% 20%, rgba(139, 92, 246, 0.08) 0%, transparent 40%),
    radial-gradient(circle at 90% 80%, rgba(59, 130, 246, 0.08) 0%, transparent 45%);
  background-attachment: fixed;
}

h1, h2, h3, h4, h5, h6 {
  font-family: var(--font-display);
  font-weight: 600;
  letter-spacing: -0.02em;
}

a {
  color: var(--accent-secondary);
  text-decoration: none;
  transition: var(--transition-smooth);
}

a:hover {
  color: var(--accent-primary);
  text-decoration: underline;
}

/* Glassmorphism utility */
.glass-panel {
  background: var(--glass-bg);
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
  border: 1px solid var(--glass-border);
  box-shadow: 0 8px 32px var(--glass-shadow);
  border-radius: 16px;
  transition: var(--transition-smooth);
}

.glass-panel:hover {
  border-color: var(--glass-border-hover);
}

/* Glowing text & borders */
.glow-text-purple {
  text-shadow: 0 0 15px rgba(139, 92, 246, 0.4);
}

.glow-text-green {
  text-shadow: 0 0 15px rgba(16, 185, 129, 0.4);
}

.glow-text-red {
  text-shadow: 0 0 15px rgba(239, 68, 68, 0.4);
}

/* Main Layout */
.app-container {
  max-width: 1200px;
  margin: 0 auto;
  padding: 2.5rem 1.5rem;
  display: flex;
  flex-direction: column;
  gap: 2rem;
  min-height: 100vh;
}

/* Header */
.app-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  border-bottom: 1px solid var(--glass-border);
  padding-bottom: 1.5rem;
}

.logo-container {
  display: flex;
  align-items: center;
  gap: 0.75rem;
}

.logo-badge {
  background: linear-gradient(135deg, var(--accent-primary) 0%, var(--accent-secondary) 100%);
  color: white;
  width: 40px;
  height: 40px;
  border-radius: 12px;
  display: flex;
  align-items: center;
  justify-content: center;
  font-weight: 800;
  box-shadow: 0 0 20px rgba(139, 92, 246, 0.3);
}

.logo-text h1 {
  font-size: 1.5rem;
  font-weight: 700;
  background: linear-gradient(to right, #ffffff, #d1d5db);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
}

.logo-text span {
  font-size: 0.75rem;
  color: var(--text-secondary);
  letter-spacing: 0.05em;
  text-transform: uppercase;
}

.header-actions {
  display: flex;
  align-items: center;
  gap: 1rem;
}

/* Button Component Styles */
.btn-primary {
  background: linear-gradient(135deg, var(--accent-primary) 0%, var(--accent-secondary) 100%);
  border: none;
  color: white;
  padding: 0.75rem 1.5rem;
  border-radius: 10px;
  font-family: var(--font-display);
  font-weight: 600;
  cursor: pointer;
  display: flex;
  align-items: center;
  gap: 0.5rem;
  transition: var(--transition-bounce);
  box-shadow: 0 4px 15px rgba(139, 92, 246, 0.2);
}

.btn-primary:hover {
  transform: translateY(-2px);
  box-shadow: 0 6px 20px rgba(139, 92, 246, 0.4);
}

.btn-primary:active {
  transform: translateY(0);
}

.btn-primary:disabled {
  opacity: 0.6;
  cursor: not-allowed;
  transform: none;
  box-shadow: none;
}

.btn-secondary {
  background: rgba(255, 255, 255, 0.05);
  border: 1px solid var(--glass-border);
  color: var(--text-primary);
  padding: 0.75rem 1.5rem;
  border-radius: 10px;
  font-family: var(--font-display);
  font-weight: 600;
  cursor: pointer;
  display: flex;
  align-items: center;
  gap: 0.5rem;
  transition: var(--transition-smooth);
}

.btn-secondary:hover {
  background: rgba(255, 255, 255, 0.1);
  border-color: var(--glass-border-hover);
}

/* Search Bar Area */
.search-container {
  display: flex;
  flex-direction: column;
  gap: 1.5rem;
  margin: 1rem 0;
}

.search-box {
  display: flex;
  gap: 0.75rem;
}

.search-input-wrapper {
  position: relative;
  flex: 1;
}

.search-icon-decor {
  position: absolute;
  left: 1.25rem;
  top: 50%;
  transform: translateY(-50%);
  color: var(--text-muted);
}

.search-input {
  width: 100%;
  background: rgba(255, 255, 255, 0.03);
  border: 1px solid var(--glass-border);
  border-radius: 12px;
  padding: 1.1rem 1.25rem 1.1rem 3.25rem;
  color: var(--text-primary);
  font-size: 1.1rem;
  font-family: var(--font-body);
  transition: var(--transition-smooth);
}

.search-input:focus {
  outline: none;
  border-color: var(--accent-primary);
  box-shadow: 0 0 15px rgba(139, 92, 246, 0.15), inset 0 0 8px rgba(139, 92, 246, 0.05);
  background: rgba(255, 255, 255, 0.05);
}

.search-input::placeholder {
  color: var(--text-muted);
}

.quick-tags {
  display: flex;
  align-items: center;
  gap: 0.75rem;
  flex-wrap: wrap;
  font-size: 0.85rem;
}

.quick-tag-label {
  color: var(--text-muted);
}

.tag-btn {
  background: rgba(255, 255, 255, 0.03);
  border: 1px solid var(--glass-border);
  color: var(--text-secondary);
  padding: 0.35rem 0.85rem;
  border-radius: 20px;
  cursor: pointer;
  transition: var(--transition-smooth);
}

.tag-btn:hover {
  background: rgba(139, 92, 246, 0.1);
  color: var(--text-primary);
  border-color: rgba(139, 92, 246, 0.3);
}

/* Settings Modal Drawer */
.settings-overlay {
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  background: rgba(0, 0, 0, 0.6);
  backdrop-filter: blur(4px);
  z-index: 1000;
  opacity: 0;
  pointer-events: none;
  transition: var(--transition-smooth);
}

.settings-overlay.active {
  opacity: 1;
  pointer-events: auto;
}

.settings-drawer {
  position: fixed;
  top: 0;
  right: -420px;
  width: 420px;
  height: 100%;
  background: var(--bg-secondary);
  border-left: 1px solid var(--glass-border);
  box-shadow: -10px 0 30px rgba(0, 0, 0, 0.5);
  z-index: 1001;
  padding: 2.5rem;
  display: flex;
  flex-direction: column;
  gap: 2rem;
  transition: transform 0.4s cubic-bezier(0.16, 1, 0.3, 1);
}

.settings-overlay.active .settings-drawer {
  transform: translateX(-420px);
}

.settings-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.settings-title {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  font-size: 1.25rem;
  font-weight: 700;
}

.settings-close {
  background: none;
  border: none;
  color: var(--text-muted);
  cursor: pointer;
  font-size: 1.5rem;
  transition: var(--transition-smooth);
}

.settings-close:hover {
  color: var(--text-primary);
}

.settings-form {
  display: flex;
  flex-direction: column;
  gap: 1.5rem;
}

.form-group {
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
}

.form-group label {
  font-size: 0.875rem;
  color: var(--text-secondary);
  font-weight: 500;
  display: flex;
  justify-content: space-between;
}

.form-group label span {
  font-size: 0.75rem;
  color: var(--text-muted);
}

.form-input {
  background: rgba(255, 255, 255, 0.03);
  border: 1px solid var(--glass-border);
  border-radius: 8px;
  padding: 0.75rem;
  color: var(--text-primary);
  font-family: monospace;
  font-size: 0.9rem;
  transition: var(--transition-smooth);
}

.form-input:focus {
  outline: none;
  border-color: var(--accent-primary);
  background: rgba(255, 255, 255, 0.05);
}

.form-toggle {
  display: flex;
  align-items: center;
  justify-content: space-between;
  background: rgba(255, 255, 255, 0.02);
  border: 1px solid var(--glass-border);
  padding: 1rem;
  border-radius: 12px;
  margin-top: 0.5rem;
}

.toggle-label {
  display: flex;
  flex-direction: column;
}

.toggle-label-main {
  font-size: 0.95rem;
  font-weight: 600;
}

.toggle-label-sub {
  font-size: 0.75rem;
  color: var(--text-muted);
}

/* Custom switch checkbox styling */
.switch {
  position: relative;
  display: inline-block;
  width: 48px;
  height: 24px;
}

.switch input {
  opacity: 0;
  width: 0;
  height: 0;
}

.slider {
  position: absolute;
  cursor: pointer;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background-color: rgba(255, 255, 255, 0.1);
  transition: .4s;
  border-radius: 24px;
  border: 1px solid var(--glass-border);
}

.slider:before {
  position: absolute;
  content: "";
  height: 16px;
  width: 16px;
  left: 3px;
  bottom: 3px;
  background-color: var(--text-primary);
  transition: .3s cubic-bezier(0.16, 1, 0.3, 1);
  border-radius: 50%;
}

input:checked + .slider {
  background-color: var(--accent-primary);
  border-color: rgba(139, 92, 246, 0.5);
}

input:checked + .slider:before {
  transform: translateX(24px);
}

/* Terminal Log Container */
.terminal-container {
  display: flex;
  flex-direction: column;
  border-radius: 16px;
  overflow: hidden;
  box-shadow: 0 10px 40px rgba(0, 0, 0, 0.6);
  border: 1px solid var(--glass-border);
}

.terminal-header {
  background: rgba(15, 21, 35, 0.9);
  padding: 0.75rem 1.25rem;
  display: flex;
  align-items: center;
  justify-content: space-between;
  border-bottom: 1px solid var(--glass-border);
}

.terminal-dots {
  display: flex;
  gap: 0.5rem;
}

.terminal-dot {
  width: 12px;
  height: 12px;
  border-radius: 50%;
}

.dot-red { background: #EF4444; }
.dot-yellow { background: #F59E0B; }
.dot-green { background: #10B981; }

.terminal-title {
  font-family: monospace;
  font-size: 0.85rem;
  color: var(--text-secondary);
}

.terminal-body {
  background: #06090F;
  font-family: 'Courier New', Courier, monospace;
  padding: 1.5rem;
  min-height: 250px;
  max-height: 400px;
  overflow-y: auto;
  display: flex;
  flex-direction: column;
  gap: 0.75rem;
  font-size: 0.9rem;
}

.log-entry {
  display: flex;
  gap: 0.75rem;
  line-height: 1.5;
  animation: fadeIn 0.3s ease forwards;
}

.log-time {
  color: var(--text-muted);
  user-select: none;
}

.log-bullet {
  color: var(--accent-primary);
}

.log-text {
  flex: 1;
}

.log-phase-profile { color: var(--accent-secondary); }
.log-phase-financials { color: var(--warning); }
.log-phase-moat { color: var(--accent-primary); }
.log-phase-sentiment { color: #EC4899; }
.log-phase-synthesis { color: var(--success); }

/* Pulse animation for active terminal step */
.pulse-loader {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  margin-left: 0.5rem;
}

.pulse-bubble {
  width: 6px;
  height: 6px;
  background-color: var(--text-secondary);
  border-radius: 50%;
  animation: pulse-bubble 1.4s infinite ease-in-out both;
}

.pulse-bubble:nth-child(1) { animation-delay: -0.32s; }
.pulse-bubble:nth-child(2) { animation-delay: -0.16s; }

/* Report Layout */
.report-layout {
  display: flex;
  flex-direction: column;
  gap: 2rem;
  animation: slideUp 0.6s cubic-bezier(0.16, 1, 0.3, 1) forwards;
}

/* Decision Ribbon */
.decision-card {
  position: relative;
  overflow: hidden;
  padding: 2rem;
  display: flex;
  flex-direction: column;
  gap: 1.25rem;
}

.decision-card::before {
  content: '';
  position: absolute;
  top: 0;
  left: 0;
  width: 6px;
  height: 100%;
}

.decision-card.decision-invest::before {
  background: var(--success);
  box-shadow: 0 0 15px var(--success);
}

.decision-card.decision-pass::before {
  background: var(--danger);
  box-shadow: 0 0 15px var(--danger);
}

.decision-header-row {
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
  flex-wrap: wrap;
  gap: 1.5rem;
}

.decision-badge {
  font-family: var(--font-display);
  font-weight: 800;
  font-size: 1.5rem;
  padding: 0.5rem 1.5rem;
  border-radius: 8px;
  letter-spacing: 0.05em;
  display: flex;
  align-items: center;
  gap: 0.5rem;
}

.decision-badge.invest {
  background: var(--success-glow);
  color: var(--success);
  border: 1px solid rgba(16, 185, 129, 0.3);
}

.decision-badge.pass {
  background: var(--danger-glow);
  color: var(--danger);
  border: 1px solid rgba(239, 68, 68, 0.3);
}

.company-title-info h2 {
  font-size: 2.25rem;
  font-weight: 800;
}

.company-title-info p {
  color: var(--text-secondary);
  font-size: 1rem;
  margin-top: 0.25rem;
}

.thesis-box {
  background: rgba(255, 255, 255, 0.02);
  border-left: 3px solid var(--accent-primary);
  padding: 1.25rem;
  border-radius: 0 8px 8px 0;
}

.thesis-box h4 {
  font-size: 0.85rem;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  color: var(--accent-primary);
  margin-bottom: 0.5rem;
}

.thesis-box p {
  font-size: 1.1rem;
  line-height: 1.6;
  color: var(--text-primary);
  font-style: italic;
}

/* Scores Grid */
.scores-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));
  gap: 1.25rem;
}

.score-card {
  padding: 1.5rem;
  display: flex;
  align-items: center;
  gap: 1.25rem;
}

.score-circle-wrapper {
  position: relative;
  width: 60px;
  height: 60px;
  display: flex;
  align-items: center;
  justify-content: center;
}

.score-svg {
  width: 60px;
  height: 60px;
  transform: rotate(-90deg);
}

.score-bg-ring {
  fill: none;
  stroke: rgba(255, 255, 255, 0.05);
  stroke-width: 4px;
}

.score-fill-ring {
  fill: none;
  stroke: var(--accent-primary);
  stroke-width: 4px;
  stroke-linecap: round;
  transition: stroke-dashoffset 1s ease-in-out;
}

.score-fill-ring.color-success { stroke: var(--success); }
.score-fill-ring.color-warning { stroke: var(--warning); }
.score-fill-ring.color-danger { stroke: var(--danger); }

.score-text-val {
  position: absolute;
  font-family: var(--font-display);
  font-weight: 700;
  font-size: 1rem;
  color: var(--text-primary);
}

.score-label-group {
  display: flex;
  flex-direction: column;
  gap: 0.25rem;
}

.score-label {
  font-size: 0.8rem;
  color: var(--text-secondary);
  text-transform: uppercase;
  letter-spacing: 0.05em;
}

.score-desc {
  font-size: 1.15rem;
  font-weight: 700;
  color: var(--text-primary);
}

/* Tabs System */
.tabs-container {
  display: flex;
  flex-direction: column;
  gap: 1.5rem;
}

.tabs-nav {
  display: flex;
  border-bottom: 1px solid var(--glass-border);
  gap: 1rem;
  overflow-x: auto;
}

.tab-button {
  background: none;
  border: none;
  color: var(--text-muted);
  font-family: var(--font-display);
  font-weight: 600;
  font-size: 1rem;
  padding: 1rem 0.5rem;
  cursor: pointer;
  transition: var(--transition-smooth);
  position: relative;
  white-space: nowrap;
}

.tab-button:hover {
  color: var(--text-primary);
}

.tab-button.active {
  color: var(--accent-primary);
}

.tab-button.active::after {
  content: '';
  position: absolute;
  bottom: -1px;
  left: 0;
  width: 100%;
  height: 2px;
  background: var(--accent-primary);
  box-shadow: 0 0 10px var(--accent-primary);
}

.tab-content {
  line-height: 1.7;
  color: var(--text-secondary);
  font-size: 1.05rem;
  animation: fadeIn 0.4s ease forwards;
}

/* Markdown styling inside tab content */
.tab-content h3, .tab-content h4 {
  color: var(--text-primary);
  margin: 1.5rem 0 0.75rem 0;
}

.tab-content h3:first-child, .tab-content h4:first-child {
  margin-top: 0;
}

.tab-content p {
  margin-bottom: 1rem;
}

.tab-content ul, .tab-content ol {
  margin: 0.75rem 0 1.25rem 1.5rem;
}

.tab-content li {
  margin-bottom: 0.5rem;
}

.tab-content strong {
  color: var(--text-primary);
}

/* Pros and Cons */
.pros-cons-grid {
  display: grid;
  grid-template-columns: 1fr;
  gap: 1.5rem;
}

@media (min-width: 768px) {
  .pros-cons-grid {
    grid-template-columns: 1fr 1fr;
  }
}

.pro-con-card {
  padding: 1.75rem;
  display: flex;
  flex-direction: column;
  gap: 1.25rem;
}

.pro-con-title {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  font-size: 1.25rem;
  font-weight: 700;
}

.pro-con-title.pro {
  color: var(--success);
}

.pro-con-title.con {
  color: var(--danger);
}

.pro-con-list {
  display: flex;
  flex-direction: column;
  gap: 0.85rem;
  list-style: none;
}

.pro-con-item {
  display: flex;
  gap: 0.75rem;
  font-size: 0.95rem;
  line-height: 1.5;
  color: var(--text-secondary);
}

.pro-con-item svg {
  flex-shrink: 0;
  margin-top: 0.2rem;
}

/* Risks Analysis Section */
.risks-section {
  display: flex;
  flex-direction: column;
  gap: 1.25rem;
}

.risks-section h3 {
  font-size: 1.35rem;
  display: flex;
  align-items: center;
  gap: 0.5rem;
}

.risk-table-container {
  overflow-x: auto;
  border-radius: 12px;
  border: 1px solid var(--glass-border);
}

.risk-table {
  width: 100%;
  border-collapse: collapse;
  text-align: left;
  font-size: 0.95rem;
}

.risk-table th {
  background: rgba(255, 255, 255, 0.03);
  color: var(--text-primary);
  font-weight: 600;
  padding: 1rem;
  border-bottom: 1px solid var(--glass-border);
}

.risk-table td {
  padding: 1rem;
  border-bottom: 1px solid var(--glass-border);
  color: var(--text-secondary);
}

.risk-table tr:last-child td {
  border-bottom: none;
}

/* Badges for impact/probability */
.pill-badge {
  display: inline-block;
  padding: 0.25rem 0.75rem;
  border-radius: 20px;
  font-size: 0.8rem;
  font-weight: 600;
  text-transform: uppercase;
}

.pill-badge.level-high {
  background: var(--danger-glow);
  color: var(--danger);
  border: 1px solid rgba(239, 68, 68, 0.2);
}

.pill-badge.level-medium {
  background: rgba(245, 158, 11, 0.1);
  color: var(--warning);
  border: 1px solid rgba(245, 158, 11, 0.2);
}

.pill-badge.level-low {
  background: var(--success-glow);
  color: var(--success);
  border: 1px solid rgba(16, 185, 129, 0.2);
}

/* Reference Sources Section */
.sources-section {
  display: flex;
  flex-direction: column;
  gap: 1rem;
}

.sources-section h3 {
  font-size: 1.25rem;
  display: flex;
  align-items: center;
  gap: 0.5rem;
  color: var(--text-primary);
}

.sources-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(280px, 1fr));
  gap: 1rem;
}

.source-item-card {
  padding: 1rem;
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
}

.source-item-card h4 {
  font-size: 0.95rem;
  font-weight: 600;
  color: var(--text-primary);
  line-height: 1.4;
  overflow: hidden;
  text-overflow: ellipsis;
  display: -webkit-box;
  -webkit-line-clamp: 2;
  -webkit-box-orient: vertical;
}

.source-item-card a {
  font-size: 0.8rem;
  color: var(--accent-secondary);
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

/* Animations */
@keyframes fadeIn {
  from { opacity: 0; }
  to { opacity: 1; }
}

@keyframes slideUp {
  from {
    opacity: 0;
    transform: translateY(20px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

@keyframes pulse-bubble {
  0%, 80%, 100% { transform: scale(0); }
  40% { transform: scale(1.0); }
}

/* Footer Section */
.app-footer {
  margin-top: auto;
  text-align: center;
  color: var(--text-muted);
  font-size: 0.8rem;
  border-top: 1px solid var(--glass-border);
  padding: 2rem 0;
}

/* Print/Export Styling overrides */
@media print {
  body {
    background: white !important;
    color: black !important;
  }
  .app-header, .search-container, .terminal-container, .btn-primary, .btn-secondary, .settings-overlay, .tabs-nav {
    display: none !important;
  }
  .report-layout {
    display: block !important;
  }
  .glass-panel {
    background: none !important;
    border: 1px solid #ccc !important;
    box-shadow: none !important;
  }
  .tab-content {
    display: block !important;
  }
  .tab-button {
    display: none !important;
  }
}

